def policemen_catch_thieves(arr, k):
    policemen_indices = []
    thieves_indices = []

    for i, char in enumerate(arr):
        if char == 'P':
            policemen_indices.append(i)
        elif char == 'T':
            thieves_indices.append(i)

    caught_count = 0
    p_ptr = 0
    t_ptr = 0

    while p_ptr < len(policemen_indices) and t_ptr < len(thieves_indices):
        p_pos = policemen_indices[p_ptr]
        t_pos = thieves_indices[t_ptr]

        if abs(p_pos - t_pos) <= k:
            caught_count += 1
            p_ptr += 1
            t_ptr += 1
        elif p_pos < t_pos:
            p_ptr += 1
        else: # t_pos < p_pos
            t_ptr += 1

    return caught_count
